import { useMemo } from 'react';
import { useCatalogUiSchema } from '../components/catalog/catalogUiSchema/useCatalogUiSchema';
import { HR_EMPLOYEES_CATALOG_KIND } from '../services/master/masterCodeService';

const GROUP_KEY_RE = /^employeeGroup([1-4])Code$/;

export type EmployeeGroupFormField = {
  slot: number;
  key: string;
  label: string;
  order: number;
};

const DEFAULT_GROUP_FORM_FIELDS: EmployeeGroupFormField[] = [1, 2, 3, 4].map(slot => ({
  slot,
  key: `employeeGroup${slot}Code`,
  label: `Nhóm nhân viên ${slot}`,
  order: 100 + slot * 10,
}));

/** Form nhóm NV — label + hiển thị theo ui-schema hr-employees (form.visible / order). */
export function useEmployeeGroupFormFields(catalogKind = HR_EMPLOYEES_CATALOG_KIND) {
  const { schema, loading, reload } = useCatalogUiSchema(catalogKind, true);

  const fields = useMemo((): EmployeeGroupFormField[] => {
    const fromSchema = (schema?.fields ?? [])
      .filter(f => GROUP_KEY_RE.test(f.key) && f.form?.visible !== false)
      .map(f => {
        const slot = Number(GROUP_KEY_RE.exec(f.key)?.[1] ?? 0);
        return {
          slot,
          key: f.key,
          label: f.label,
          order: f.form?.order ?? slot * 10,
        };
      })
      .filter(f => f.slot > 0)
      .sort((a, b) => a.order - b.order);

    return fromSchema.length > 0 ? fromSchema : DEFAULT_GROUP_FORM_FIELDS;
  }, [schema]);

  return { fields, loading, reload };
}
